package ir.tahamohamadi.blog.tag; import ir.tahamohamadi.common.domain.LanguageCode; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import jakarta.persistence.*; import lombok.*; import java.time.Instant; import java.util.*;
@Entity @Table(name="tag_translation") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class TagTranslation extends AuditedSoftDeletableEntity { @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="tag_id",nullable=false) private Tag tag; @Enumerated(EnumType.STRING) @Column(name="language_code",nullable=false,length=2) private LanguageCode languageCode; @Column(nullable=false,length=255) private String name; @Column(nullable=false,length=255) private String slug; @Column(name="seo_title",length=255) private String seoTitle; @Column(name="seo_description",length=500) private String seoDescription; private TagTranslation(UUID id,Tag tag,LanguageCode lang,String name,String slug,Instant at){initialize(id,at);this.tag=Objects.requireNonNull(tag);languageCode=Objects.requireNonNull(lang);this.name=requireNonBlank(name,"name");this.slug=requireNonBlank(slug,"slug");} public static TagTranslation create(UUID id,Tag tag,LanguageCode lang,String name,String slug,Instant at){return new TagTranslation(id,tag,lang,name,slug,at);} }
